function myReduce(items, fn, initial) {
  let hasInitial = arguments.length >= 3;
  let acc = hasInitial ? initial : items[0];
  let start = hasInitial ? 0 : 1;

  for (let i = start; i < items.length; i++) {
    acc = fn(acc, items[i], i);
  }
  return acc;
}

