function createEventEmitter() {
  const listeners = {};

  return {
    on(event, listener) {
      (listeners[event] ??= []).push(listener);
      return () => {
        listeners[event] = listeners[event].filter((l) => l !== listener);
      };
    },
    emit(event, data) {
      (listeners[event] || []).forEach((listener) => listener(data));
    },
  };
}

